diff --git a/lbuf.c b/lbuf.c
index 75dd0ce8..83ae5867 100644
--- a/lbuf.c
+++ b/lbuf.c
@@ -22,26 +22,45 @@ static void lopt_done(struct lopt *lo)
 
 #define lbuf_copymark(dst, src) { dst[0] = src[0]; dst[1] = src[1]; }
 
-/* find a mark id, returning its row & off pair */
-static int *mark_find(int *mark, int n, int id)
+/* slot of a mark id or the empty slot to insert it at */
+static int *mark_slot(struct mhash *h, int id)
 {
-	for (int i = 0; i < n * 3; i += 3)
-		if (mark[i] == id)
-			return mark + i + 1;
-	return NULL;
+	int i = id & (h->sz - 1);
+	while (h->slot[i * 3] >= 0 && h->slot[i * 3] != id)
+		i = (i + 1) & (h->sz - 1);
+	return h->slot + i * 3;
 }
 
-static void mark_set(int **mark, int *n, int id, int pos, int off)
-{
-	int *m = mark_find(*mark, *n, id);
-	if (!m) {
-		*mark = erealloc(*mark, (*n + 1) * 3 * sizeof(int));
-		m = *mark + *n * 3;
-		*m++ = id;
-		(*n)++;
+/* find a mark id, returning its row & off pair */
+static int *mark_find(struct mhash *h, int id)
+{
+	int *m = h ? mark_slot(h, id) : NULL;
+	return m && m[0] >= 0 ? m + 1 : NULL;
+}
+
+static void mark_set(struct mhash **ph, int id, int pos, int off)
+{
+	struct mhash *h = *ph;
+	if (!h || (h->n + 1) * 4 > h->sz * 3) {
+		int i, nsz = h ? h->sz * 2 : 8;
+		struct mhash *nh = emalloc(sizeof(*nh) + nsz * 3 * sizeof(int));
+		nh->sz = nsz;
+		nh->n = h ? h->n : 0;
+		memset(nh->slot, -1, nsz * 3 * sizeof(int));
+		for (i = 0; h && i < h->sz * 3; i += 3)
+			if (h->slot[i] >= 0)
+				memcpy(mark_slot(nh, h->slot[i]),
+					h->slot + i, 3 * sizeof(int));
+		free(h);
+		*ph = h = nh;
 	}
-	m[0] = pos;
-	m[1] = off;
+	int *m = mark_slot(h, id);
+	if (m[0] < 0) {
+		m[0] = id;
+		h->n++;
+	}
+	m[1] = pos;
+	m[2] = off;
 }
 
 void lbuf_mark(struct lbuf *lb, int mk, int pos, int off)
@@ -54,8 +73,8 @@ void lbuf_mark(struct lbuf *lb, int mk, int pos, int off)
 	} else if (mk == ']') {
 		lb->mark_se[0] = pos;
 		lb->mark_se[1] = off;
-	} else
-		mark_set(&lb->mark, &lb->mark_n, mk, pos, off);
+	} else if (mk >= 0)
+		mark_set(&lb->mark, mk, pos, off);
 }
 
 int lbuf_jump(struct lbuf *lb, int mk, int *pos, int *off)
@@ -68,7 +87,7 @@ int lbuf_jump(struct lbuf *lb, int mk, int *pos, int *off)
 	else if (mk == ']')
 		m = lb->mark_se;
 	else
-		m = mark_find(lb->mark, lb->mark_n, mk);
+		m = mk >= 0 ? mark_find(lb->mark, mk) : NULL;
 	if (!m || m[0] < 0)
 		return 1;
 	*pos = m[0];
@@ -129,14 +148,16 @@ static int lbuf_replace(struct lbuf *lb, sbuf *sb, char *s, struct lopt *lo, int
 	lb->ln_n += n_ins - n_del;
 	for (i = 0; i < n_ins; i++)
 		lb->ln[pos + i] = *((char**)sb->s + i);
-	for (i = 0; i < lb->mark_n; i++) {	/* updating marks */
-		int *m = lb->mark + i * 3, *lm;
+	for (i = 0; lb->mark && i < lb->mark->sz * 3; i += 3) {	/* updating marks */
+		int *m = lb->mark->slot + i, *lm;
+		if (m[0] < 0)
+			continue;
 		if (m[1] >= pos + n_ins && m[1] < pos + n_del) {
-			mark_set(&lo->mark, &lo->mark_n, m[0], m[1], m[2]);
+			mark_set(&lo->mark, m[0], m[1], m[2]);
 			m[1] = n_ins ? pos + n_ins - 1 : -1;
 		} else if (m[1] >= pos + n_del) {
 			m[1] += n_ins - n_del;
-		} else if ((lm = mark_find(lo->mark, lo->mark_n, m[0])))
+		} else if ((lm = mark_find(lo->mark, m[0])))
 			lbuf_copymark((m + 1), lm)
 	}
 	return n_ins;
@@ -185,7 +206,6 @@ struct lopt *lbuf_opt(struct lbuf *lb, int beg, int o1, int n_del)
 	for (int i = 0; i < n_del; i++)
 		lo->del[i] = lb->ln[beg + i];
 	lo->mark = NULL;
-	lo->mark_n = 0;
 	lo->mark_sb[0] = -1;
 	lo->mark_se[0] = -1;
 	lo->pos = beg;
